function solve(grid, x, y, k) {
    // Create a copy of the grid to avoid modifying the original
    let matrix = grid.map(row => [...row]);

    // Extract the submatrix
    let submatrix = [];
    for (let i = 0; i < k; i++) {
        submatrix.push(matrix[x + i].slice(y, y + k));
    }

    // Reverse the submatrix
    let reversedSubmatrix = submatrix.slice().reverse();

    // Replace the original submatrix with the reversed one
    for (let i = 0; i < k; i++) {
        for (let j = 0; j < k; j++) {
            matrix[x + i][y + j] = reversedSubmatrix[i][j];
        }
    }

    return matrix;
}
